-- Debug script to identify subject creation issues\n-- Run this to check what might be causing the validation errors\n\n-- Step 1: Check subjects table structure\nSELECT 'Subjects table structure:' as check_step;\nDESCRIBE subjects;\n\n-- Step 2: Check constraints on subjects table\nSELECT 'Constraints on subjects table:' as check_step;\nSELECT \n    CONSTRAINT_NAME,\n    CONSTRAINT_TYPE,\n    TABLE_NAME\nFROM INFORMATION_SCHEMA.TABLE_CONSTRAINTS \nWHERE TABLE_SCHEMA = DATABASE() \nAND TABLE_NAME = 'subjects';\n\n-- Step 3: Check if the classes exist\nSELECT 'Checking if classes exist:' as check_step;\nSELECT \n    class_code,\n    class_name,\n    section,\n    school_id,\n    branch_id,\n    status\nFROM classes \nWHERE class_code IN ('CLS0003', 'CLS0004', 'CLS0022')\nAND school_id = 'SCH/1'\nAND branch_id = 'BRCH00013';\n\n-- Step 4: Check if school and branch exist\nSELECT 'Checking school existence:' as check_step;\nSELECT school_id, school_name, status \nFROM school_setup \nWHERE school_id = 'SCH/1';\n\nSELECT 'Checking branch existence:' as check_step;\nSELECT school_id, branch_id, branch_name, status \nFROM school_locations \nWHERE school_id = 'SCH/1' \nAND branch_id = 'BRCH00013';\n\n-- Step 5: Check existing subjects for these classes\nSELECT 'Existing subjects for these classes:' as check_step;\nSELECT \n    subject_code,\n    subject,\n    class_code,\n    section,\n    type,\n    status,\n    school_id,\n    branch_id\nFROM subjects \nWHERE class_code IN ('CLS0003', 'CLS0004', 'CLS0022')\nAND school_id = 'SCH/1'\nAND branch_id = 'BRCH00013'\nLIMIT 10;\n\n-- Step 6: Test manual subject creation\nSELECT 'Testing manual subject creation:' as test_step;\n\n-- Try to create a test subject manually\n-- UNCOMMENT THE FOLLOWING TO TEST:\n/*\nINSERT INTO subjects (\n    subject_code,\n    subject,\n    school_id,\n    status,\n    section,\n    type,\n    is_elective,\n    branch_id,\n    class_code,\n    created_at,\n    updated_at\n) VALUES (\n    'TEST001',\n    'Test Subject',\n    'SCH/1',\n    'Active',\n    'PRIMARY',\n    'core',\n    FALSE,\n    'BRCH00013',\n    'CLS0003',\n    NOW(),\n    NOW()\n);\n*/\n\n-- Step 7: Check for any triggers or procedures that might interfere\nSELECT 'Checking for triggers:' as check_step;\nSELECT \n    TRIGGER_NAME,\n    EVENT_MANIPULATION,\n    TRIGGER_SCHEMA,\n    TRIGGER_NAME\nFROM INFORMATION_SCHEMA.TRIGGERS \nWHERE TABLE_SCHEMA = DATABASE() \nAND TABLE_NAME = 'subjects';\n\n-- Step 8: Check current AUTO_INCREMENT value\nSELECT 'Checking AUTO_INCREMENT status:' as check_step;\nSELECT \n    TABLE_NAME,\n    AUTO_INCREMENT\nFROM INFORMATION_SCHEMA.TABLES \nWHERE TABLE_SCHEMA = DATABASE() \nAND TABLE_NAME = 'subjects';\n\n-- Step 9: Check for any foreign key constraints\nSELECT 'Foreign key constraints:' as check_step;\nSELECT \n    CONSTRAINT_NAME,\n    TABLE_NAME,\n    COLUMN_NAME,\n    REFERENCED_TABLE_NAME,\n    REFERENCED_COLUMN_NAME\nFROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE \nWHERE TABLE_SCHEMA = DATABASE() \nAND TABLE_NAME = 'subjects'\nAND REFERENCED_TABLE_NAME IS NOT NULL;\n\n-- Step 10: Show sample working subject for comparison\nSELECT 'Sample working subject for comparison:' as check_step;\nSELECT * FROM subjects \nWHERE school_id = 'SCH/1' \nAND status = 'Active'\nLIMIT 1;\n"